'use client'
import { cn, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import styles from './breadcrumb.module.css'

export interface BreadcrumbItem {
  label: string
  href?: string
}

export interface BreadcrumbProps {
  items: BreadcrumbItem[]
  maxVisible?: number
  className?: string
  /** Accessible label for the nav landmark */
  ariaLabel?: string
}

export function Breadcrumb({ items, maxVisible, className, ariaLabel }: BreadcrumbProps) {
  useSignals()
  const resolvedAriaLabel = ariaLabel ?? t(builtin.breadcrumb.nav)
  let visible = items
  const first = items[0]
  if (first !== undefined && maxVisible !== undefined && items.length > maxVisible) {
    visible = [first, { label: '…' }, ...items.slice(items.length - (maxVisible - 2))]
  }

  return (
    <nav aria-label={resolvedAriaLabel} className={cn(styles['breadcrumb'], className)}>
      <ol>
        {visible.map((item, index) => {
          const isLast = index === visible.length - 1
          return (
            <li key={`${index}-${item.label}`}>
              {isLast ? (
                <span aria-current="page">{item.label}</span>
              ) : item.href !== undefined ? (
                <a href={item.href}>{item.label}</a>
              ) : (
                <span>{item.label}</span>
              )}
            </li>
          )
        })}
      </ol>
    </nav>
  )
}

@layer cascivo.component {
  .breadcrumb {
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    line-height: var(--cascivo-leading-normal);

    & ol {
      display: flex;
      flex-wrap: wrap;
      align-items: center;
      gap: var(--cascivo-space-2);
      margin: 0;
      padding: 0;
      list-style: none;
    }

    & li {
      display: inline-flex;
      align-items: center;
      gap: var(--cascivo-space-2);
      color: var(--cascivo-color-text-muted);
    }

    /* Separator — alt text '' keeps it out of the accessibility tree */
    & li + li::before {
      content: '/' / '';
      color: var(--cascivo-color-text-subtle);
    }

    & a {
      color: var(--cascivo-color-text-muted);
      text-decoration: none;
      border-radius: var(--cascivo-radius-item);
      transition: color var(--cascivo-duration-150) var(--cascivo-ease-out);

      &:hover {
        color: var(--cascivo-color-text);
        text-decoration: underline;
      }

      &:focus-visible {
        outline: none;
        box-shadow: var(--cascivo-focus-ring);
      }
    }

    & [aria-current='page'] {
      color: var(--cascivo-color-text);
      font-weight: var(--cascivo-font-medium);
    }
  }
}
